#!/usr/bin/env python3
"""schema_compat_check.py

Classifies telemetry schema changes as breaking or non-breaking.

Usage:
  python schema_compat_check.py old_schema.yaml new_schema.yaml [--allow-breaking]

Exits 0 for non-breaking, 1 for breaking (unless --allow-breaking is passed).
"""
import sys, yaml
from dataclasses import dataclass, field
from typing import Any


@dataclass
class CompatResult:
    breaking: list[str] = field(default_factory=list)
    non_breaking: list[str] = field(default_factory=list)


def load(path: str) -> dict[str, Any]:
    with open(path) as f:
        return yaml.safe_load(f)


def req_attrs(span: dict) -> dict[str, dict]:
    return {a["name"]: a for a in span.get("required_attributes", [])}


def opt_attr_names(span: dict) -> set[str]:
    return {a["name"] for a in span.get("optional_attributes", [])}


def check_span(old: dict, new: dict, result: CompatResult) -> None:
    name = old["name"]
    old_req = req_attrs(old)
    new_req = req_attrs(new)

    for attr in old_req:
        if attr not in new_req:
            result.breaking.append(
                f"BREAKING: required attr '{attr}' removed from span '{name}'"
            )

    for attr, meta in new_req.items():
        if attr not in old_req:
            result.breaking.append(
                f"BREAKING: new required attr '{attr}' added to span '{name}' "
                f"(use optional_attributes for non-breaking addition)"
            )
        elif old_req[attr].get("type") != meta.get("type"):
            result.breaking.append(
                f"BREAKING: type of '{attr}' changed "
                f"{old_req[attr].get('type')} -> {meta.get('type')} in span '{name}'"
            )

    for attr in opt_attr_names(new) - opt_attr_names(old):
        result.non_breaking.append(
            f"INFO: new optional attr '{attr}' added to span '{name}'"
        )


def main() -> int:
    old_schema = load(sys.argv[1])
    new_schema = load(sys.argv[2])
    allow_breaking = "--allow-breaking" in sys.argv

    old_spans = {s["name"]: s for s in old_schema.get("spans", [])}
    new_spans = {s["name"]: s for s in new_schema.get("spans", [])}

    result = CompatResult()

    for span_name, old_span in old_spans.items():
        if span_name not in new_spans:
            result.breaking.append(f"BREAKING: span '{span_name}' removed entirely")
        else:
            check_span(old_span, new_spans[span_name], result)

    for span_name in set(new_spans) - set(old_spans):
        result.non_breaking.append(f"INFO: new span '{span_name}' added")

    for msg in result.non_breaking:
        print(msg)
    for msg in result.breaking:
        print(msg, file=sys.stderr)

    if result.breaking and not allow_breaking:
        print("\nCI FAILED: breaking changes require a migration plan.",
              file=sys.stderr)
        return 1
    print(f"\ncompat check passed: "
          f"{len(result.breaking)} breaking, {len(result.non_breaking)} non-breaking")
    return 0


if __name__ == "__main__":
    sys.exit(main())
